import { useState, useContext, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { FaSeedling } from 'react-icons/fa';
import AuthContext from '../context/AuthContext';
import advisoryService from '../api/advisoryService';
import Spinner from './Spinner';

function AdvisoryForm({ onAdvisoryCreated }) {
  const [formData, setFormData] = useState({
    soilType: '',
    season: '',
    waterLevel: ''
  });
  const [loading, setLoading] = useState(false);
  const { user, isAuthenticated } = useContext(AuthContext);
  const navigate = useNavigate();

  // Redirect if not authenticated
  useEffect(() => {
    if (!isAuthenticated) {
      toast.error('Please log in to get crop recommendations');
      navigate('/login');
    }
  }, [isAuthenticated, navigate]);

  const { soilType, season, waterLevel } = formData;

  const onChange = (e) => {
    setFormData((prevState) => ({
      ...prevState,
      [e.target.id]: e.target.value,
    }));
  };

  const onSubmit = async (e) => {
    e.preventDefault();

    if (!soilType || !season || !waterLevel) {
      toast.error('Please fill all fields');
      return;
    }

    setLoading(true);
    try {
      // Make sure to pass the user token for authentication
      const token = user?.token;
      const advisory = await advisoryService.createAdvisory(formData, token);
      toast.success('Advisory created successfully');
      onAdvisoryCreated(advisory);
      // Reset form
      setFormData({
        soilType: '',
        season: '',
        waterLevel: ''
      });
    } catch (error) {
      console.error('Advisory error:', error);
      const message = error.response?.data?.message || 'Something went wrong';
      toast.error(message);
      
      // If unauthorized, redirect to login
      if (error.response?.status === 401) {
        navigate('/login');
      }
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <Spinner />;
  }

  // If not authenticated, don't render the form
  if (!isAuthenticated) {
    return null;
  }

  return (
    <div className="bg-white p-6 rounded-lg shadow-md">
      <form onSubmit={onSubmit}>
        <div className="mb-4">
          <label
            htmlFor="soilType"
            className="block text-gray-700 font-medium mb-2"
          >
            Soil Type
          </label>
          <select
            id="soilType"
            value={soilType}
            onChange={onChange}
            className="w-full p-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-green-500"
            required
          >
            <option value="">Select Soil Type</option>
            <option value="clay">Clay</option>
            <option value="sandy">Sandy</option>
            <option value="loamy">Loamy</option>
            <option value="silty">Silty</option>
            <option value="peaty">Peaty</option>
            <option value="chalky">Chalky</option>
          </select>
        </div>

        <div className="mb-4">
          <label
            htmlFor="season"
            className="block text-gray-700 font-medium mb-2"
          >
            Season
          </label>
          <select
            id="season"
            value={season}
            onChange={onChange}
            className="w-full p-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-green-500"
            required
          >
            <option value="">Select Season</option>
            <option value="kharif">Kharif (Monsoon)</option>
            <option value="rabi">Rabi (Winter)</option>
            <option value="zaid">Zaid (Summer)</option>
            <option value="annual">Annual</option>
          </select>
        </div>

        <div className="mb-4">
          <label
            htmlFor="waterLevel"
            className="block text-gray-700 font-medium mb-2"
          >
            Water Availability
          </label>
          <select
            id="waterLevel"
            value={waterLevel}
            onChange={onChange}
            className="w-full p-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-green-500"
            required
          >
            <option value="">Select Water Availability</option>
            <option value="high">High</option>
            <option value="medium">Medium</option>
            <option value="low">Low</option>
          </select>
        </div>

        <button
          type="submit"
          className="w-full py-3 bg-green-600 text-white font-semibold rounded-md hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-green-500 focus:ring-offset-2"
        >
          <FaSeedling className="inline-block mr-2" />
          Get Recommendations
        </button>
      </form>
    </div>
  );
}

export default AdvisoryForm;
